#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d", &N);
    int coefficients[N + 1];
    for (int i = 0; i <= N; i++) {
        scanf("%d", &coefficients[i]);
    }
    scanf("%d", &Q);
    while (Q--) {
        int x;
        scanf("%d", &x);
        long long result = 0;
        for (int i = 0; i <= N; i++) {
            result = (result + coefficients[i] * (long long)pow(x, i)) % 786433;
        }
        printf("%lld\n", result);
    }
    return 0;
}

